[Quasi-coherent sheaves on an affine are sections-tilde]
  \label{lem:qcoh_iso_tilde_sections}
  \lean{AlgebraicGeometry.qcoh_iso_tilde_sections}
  \uses{def:standard_affine_cover}
  % SOURCE: [Stacks Project], Schemes, Tag 01HV, Lemma \texttt{lemma-spec-sheaves}
  % (read from references/stacks-schemes.tex, L691--719).
  % SOURCE QUOTE: "Let $R$ be a ring. Let $M$ be an $R$-module. Let $\widetilde M$
  % be the sheaf of $\mathcal{O}_{\Spec(R)}$-modules
  % associated to $M$.
  % \begin{enumerate}
  % \item We have $\Gamma(\Spec(R), \mathcal{O}_{\Spec(R)}) = R$.
  % \item We have $\Gamma(\Spec(R), \widetilde M) = M$ as an $R$-module.
  % \item For every $f \in R$ we have
  % $\Gamma(D(f), \mathcal{O}_{\Spec(R)}) = R_f$.
  % \item For every $f\in R$ we have $\Gamma(D(f), \widetilde M) = M_f$
  % as an $R_f$-module.
  % \end{enumerate}"
  \textit{Source: Stacks Project, Schemes, Tag 01HV, \texttt{lemma-spec-sheaves}.}
  Let \(X = \operatorname{Spec} R\) be an affine scheme and \(\mathcal{F}\) a quasi-coherent
  \(\mathcal{O}_X\)-module. Writing \(M = \Gamma(X, \mathcal{F})\) for its module of global sections,
  there is a natural isomorphism \(\mathcal{F} \cong \widetilde{M}\) of \(\mathcal{O}_X\)-modules,
  under which \(\Gamma(D(f), \mathcal{F}) = M_f\) for every \(f \in R\); in particular the sections of
  \(\mathcal{F}\) over a distinguished open \(D(f)\) are the away localisation \(M_f\). This is the
  affine quasi-coherent structure theorem (Tag 01HV, with the equivalence quasi-coherent-on-affine
  \(\simeq\) \(R\)-modules, Tag 01I8).
\end{lemma}
\begin{proof}
  \uses{def:standard_affine_cover}
  \leanok
  On an affine scheme the global-sections functor \(\mathcal{F} \mapsto \Gamma(X, \mathcal{F})\) and
  the tilde functor \(M \mapsto \widetilde{M}\) are mutually inverse equivalences between
  quasi-coherent \(\mathcal{O}_X\)-modules and \(R\)-modules; the counit
  \(\widetilde{\Gamma(X, \mathcal{F})} \to \mathcal{F}\) is an isomorphism for quasi-coherent
  \(\mathcal{F}\). By Tag 01HV the sections of \(\widetilde{M}\) over \(D(f)\) are \(M_f\), so the
  isomorphism identifies \(\Gamma(D(f), \mathcal{F})\) with \(M_f\).
\end{proof}

\begin{lemma}
[Standard-cover {\v C}ech vanishing for quasi-coherent coefficients]
  \label{lem:affine_cech_vanishing_qcoh}
  \lean{AlgebraicGeometry.affine_cech_vanishing_qcoh}
  \uses{lem:cech_acyclic_affine, lem:qcoh_iso_tilde_sections, def:affine_cover_system,
    def:has_vanishing_higher_cech}
  % SOURCE: [Stacks Project], Cohomology of Schemes, Tag 02KG, Lemma
  % \texttt{lemma-quasi-coherent-affine-cohomology-zero} (proof, condition (3)) (read
  % from references/stacks-coherent.tex, L172--173).
  % SOURCE QUOTE: "Finally, condition (3) of the lemma follows from
  % Lemma \ref{lemma-cech-cohomology-quasi-coherent-trivial}."
  \textit{Source: Stacks Project, Cohomology of Schemes, Tag 02KG
  (\texttt{lemma-quasi-coherent-affine-cohomology-zero}, proof).}
  Let \(X = \operatorname{Spec} R\) be an affine scheme and \(\mathcal{F}\) a quasi-coherent
  \(\mathcal{O}_X\)-module. Then \(\mathcal{F}\) has vanishing higher {\v C}ech cohomology for the
  affine cover system (Definition~\ref{def:affine_cover_system},
  Definition~\ref{def:has_vanishing_higher_cech}): for every standard cover \(\mathcal{U}\) and every
  \(p > 0\) one has \(\check{H}^p(\mathcal{U}, \mathcal{F}) = 0\). This is the seed that supplies
  condition (3) of the basis-comparison Lemma~\ref{lem:cech_to_cohomology_on_basis}, and is the 01I8
  globalisation of the tilde-case standard-cover vanishing.
\end{lemma}
\begin{proof}
  \uses{lem:cech_acyclic_affine, lem:qcoh_iso_tilde_sections}
  By Lemma~\ref{lem:qcoh_iso_tilde_sections} the quasi-coherent \(\mathcal{F}\) is isomorphic to
  \(\widetilde{M}\) for \(M = \Gamma(X, \mathcal{F})\), with sections over each face \(D(g_\sigma)\)
  the away localisation \(M_{g_\sigma}\). The standard-cover {\v C}ech vanishing of
  Lemma~\ref{lem:cech_acyclic_affine} applies to the tilde sheaf \(\widetilde{M}\): its section
  {\v C}ech complex over any standard cover is exact in positive degrees. Transporting along the
  isomorphism \(\mathcal{F} \cong \widetilde{M}\), which is natural in the coefficient and so induces
  an isomorphism of section {\v C}ech complexes, gives \(\check{H}^p(\mathcal{U}, \mathcal{F}) = 0\)
  for all \(p > 0\) and every standard cover \(\mathcal{U}\). Hence \(\mathcal{F}\) has vanishing
  higher {\v C}ech cohomology for the affine cover system.
\end{proof}

The {\v C}ech-to-cohomology comparison on a basis
(Lemma~\ref{lem:cech_to_cohomology_on_basis}) is proved by a dimension shift on the
coefficient module, decomposed below into four sub-lemmas: the short exact sequence of
{\v C}ech complexes coming from a basis (Lemma~\ref{lem:cech_ses_of_basis}), the
resulting stability of vanishing higher {\v C}ech cohomology under the injective
quotient (Lemma~\ref{lem:quotient_vanishing_cech}), the sheaf-cohomology base case
\(H^1(U, \mathcal{F}) = 0\) (Lemma~\ref{lem:absolute_cohomology_one_vanishing}), and the
dimension-shift induction \(H^p(U, \mathcal{F}) = 0\) for \(p > 0\)
(Lemma~\ref{lem:absolute_cohomology_pos_vanishing}). The top lemma's proof then just
chains these.

